module hpdmc_ctlif (
    input         clk,
    input         reset,
    input  [7:0]  csr_address,
    input  [31:0] csr_writedata,
    output [31:0] csr_readdata,
    input         csr_write,
    input         csr_read,
    input         pll_locked,
    output        sdram_reset_n,
    output        sdram_cke,
    output        sdram_cs_n,
    output        sdram_ras_n,
    output        sdram_cas_n,
    output        sdram_we_n,
    output [7:0]  dqs_phase_shift
);
    // Configuration registers
    reg [3:0] tRP;
    reg [3:0] tRCD;
    reg [3:0] tWR;
    reg [3:0] tRFC;
    reg [3:0] tMRD;
    reg [7:0] phase_shift;
    reg       ctrl_enable;
    reg       init_start;

    // Status registers
    wire      status_pll_locked;
    reg       status_init_done;
    reg       status_busy;

    // State machine
    reg [3:0] state;
    reg [3:0] next_state;
    reg [7:0] count;
    reg [3:0] cmd_reg;

    // State definitions
    localparam ST_RESET         = 4'd0;
    localparam ST_WAIT_PLL      = 4'd1;
    localparam ST_PRECHARGE_WAIT = 4'd2;
    localparam ST_PRECHARGE     = 4'd3;
    localparam ST_AUTO_REF1     = 4'd4;
    localparam ST_AUTO_REF2     = 4'd5;
    localparam ST_LOAD_MODE     = 4'd6;
    localparam ST_IDLE          = 4'd7;

    // Command encoding
    localparam CMD_NOP          = 4'b1111;
    localparam CMD_PRECHARGE    = 4'b0010;
    localparam CMD_AUTO_REF     = 4'b0001;
    localparam CMD_LOAD_MODE    = 4'b0000;

    // Continuous assignments
    assign sdram_cs_n  = cmd_reg[3];
    assign sdram_ras_n = cmd_reg[2];
    assign sdram_cas_n = cmd_reg[1];
    assign sdram_we_n  = cmd_reg[0];
    assign dqs_phase_shift = phase_shift;
    assign status_pll_locked = pll_locked;
    assign sdram_cke = ctrl_enable;
    assign sdram_reset_n = ~reset;

    // CSR read logic
    assign csr_readdata = 
        (csr_address == 8'h00) ? {31'b0, ctrl_enable} :
        (csr_address == 8'h01) ? {28'b0, tRP} :
        (csr_address == 8'h02) ? {28'b0, tRCD} :
        (csr_address == 8'h03) ? {28'b0, tWR} :
        (csr_address == 8'h04) ? {28'b0, tRFC} :
        (csr_address == 8'h05) ? {28'b0, tMRD} :
        (csr_address == 8'h06) ? phase_shift :
        (csr_address == 8'h07) ? {29'b0, status_busy, status_init_done, status_pll_locked} : 32'b0;

    // CSR write logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            tRP <= 4'h2;
            tRCD <= 4'h2;
            tWR <= 4'h2;
            tRFC <= 4'h4;
            tMRD <= 4'h2;
            phase_shift <= 8'h00;
            ctrl_enable <= 1'b0;
            init_start <= 1'b0;
        end else if (csr_write) begin
            case (csr_address)
                8'h00: ctrl_enable <= csr_writedata[0];
                8'h01: tRP <= csr_writedata[3:0];
                8'h02: tRCD <= csr_writedata[3:0];
                8'h03: tWR <= csr_writedata[3:0];
                8'h04: tRFC <= csr_writedata[3:0];
                8'h05: tMRD <= csr_writedata[3:0];
                8'h06: phase_shift <= csr_writedata[7:0];
            endcase
        end
    end

    // State machine registers
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= ST_RESET;
            count <= 8'd0;
            cmd_reg <= CMD_NOP;
            status_init_done <= 1'b0;
            status_busy <= 1'b0;
        end else begin
            state <= next_state;

            case (state)
                ST_RESET: begin
                    cmd_reg <= CMD_NOP;
                    status_init_done <= 1'b0;
                    status_busy <= 1'b0;
                end

                ST_WAIT_PLL: begin
                    if (pll_locked) begin
                        count <= tRP;
                    end
                end

                ST_PRECHARGE_WAIT: begin
                    if (count > 0) count <= count - 1;
                end

                ST_PRECHARGE: begin
                    cmd_reg <= CMD_PRECHARGE;
                    count <= tRP;
                end

                ST_AUTO_REF1: begin
                    cmd_reg <= CMD_AUTO_REF;
                    count <= tRFC;
                end

                ST_AUTO_REF2: begin
                    cmd_reg <= CMD_AUTO_REF;
                    count <= tRFC;
                end

                ST_LOAD_MODE: begin
                    cmd_reg <= CMD_LOAD_MODE;
                    count <= tMRD;
                end

                ST_IDLE: begin
                    cmd_reg <= CMD_NOP;
                    status_init_done <= 1'b1;
                    status_busy <= 1'b0;
                end

                default: cmd_reg <= CMD_NOP;
            endcase
        end
    end

    // State machine next-state logic
    always @(*) begin
        next_state = state;
        case (state)
            ST_RESET: 
                next_state = ST_WAIT_PLL;

            ST_WAIT_PLL: 
                if (pll_locked) 
                    next_state = ST_PRECHARGE_WAIT;

            ST_PRECHARGE_WAIT: 
                if (count == 0) 
                    next_state = ST_PRECHARGE;

            ST_PRECHARGE: 
                next_state = ST_AUTO_REF1;

            ST_AUTO_REF1: 
                if (count == 0) 
                    next_state = ST_AUTO_REF2;

            ST_AUTO_REF2: 
                if (count == 0) 
                    next_state = ST_LOAD_MODE;

            ST_LOAD_MODE: 
                if (count == 0) 
                    next_state = ST_IDLE;

            ST_IDLE: 
                if (~status_init_done) 
                    next_state = ST_RESET;
        endcase
    end
endmodule

module zxbus (
  input clk,
  input reset,
  input [7:0] zxid,
  output [7:0] zxid_out,
  output buf_oe_n,
  output buf_dir,
  input IORQ,
  input MREQ,
  input RD,
  input WR,
  input A0, A1, A2, A3, A4, A5, A6, A7, A8, A9, A10, A11, A12, A13, A14, A15,
  output led,
  output [7:0] init,
  output [7:0] test_reg,
  output [7:0] data_reg
);

  wire [15:0] A = {A15, A14, A13, A12, A11, A10, A9, A8, A7, A6, A5, A4, A3, A2, A1, A0};
  wire read_cycle = ~IORQ & MREQ & ~RD & WR;
  wire write_cycle = ~IORQ & MREQ & RD & ~WR;
  wire address_match = (A == 16'h0033) || (A == 16'h003B) || (A == 16'h00B3) || (A == 16'h00BB);

  assign buf_oe_n = ~(read_cycle & address_match);
  assign buf_dir = read_cycle & address_match;

  reg [7:0] init_reg;
  reg [7:0] test_reg_reg;
  reg [7:0] data_reg_reg;
  reg aien;
  reg led_reg;

  assign init = init_reg;
  assign test_reg = test_reg_reg;
  assign data_reg = data_reg_reg;
  assign led = led_reg;

  reg [7:0] zxid_out_reg;
  assign zxid_out = zxid_out_reg;

  always @(*) begin
    if (read_cycle & address_match) begin
      case (A)
        16'h0033: zxid_out_reg = init_reg;
        16'h003B: zxid_out_reg = test_reg_reg;
        16'h00B3: zxid_out_reg = data_reg_reg;
        16'h00BB: zxid_out_reg = {7'b0, aien};
        default: zxid_out_reg = 8'b0;
      endcase
    end
    else begin
      zxid_out_reg = 8'b0;
    end
  end

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      init_reg <= 8'h00;
      test_reg_reg <= 8'h00;
      data_reg_reg <= 8'h00;
      aien <= 1'b0;
      led_reg <= 1'b0;
    end
    else begin
      if (write_cycle & address_match) begin
        case (A)
          16'h0033: init_reg <= zxid;
          16'h003B: test_reg_reg <= zxid;
          16'h00B3: data_reg_reg <= zxid;
          16'h00BB: begin
            aien <= zxid[0];
            led_reg <= ~led_reg;
          end
        endcase
      end
    end
  end

endmodule

module hi_simulate (
  input ck_1356meg,
  input [7:0] adc_d,
  input [1:0] mod_type,
  output pwr_hi,
  output pwr_lo,
  output adc_clk,
  output ssp_clk,
  output ssp_frame,
  output pwr_oe1,
  output pwr_oe2,
  output pwr_oe3,
  output pwr_oe4,
  output ssp_din,
  output dbg
);
  // Power management (constant low)
  assign pwr_hi = 1'b0;
  assign pwr_lo = 1'b0;

  // Clock generation
  assign adc_clk = ck_1356meg;

  reg [4:0] clk_div = 0;
  reg ssp_clk_reg = 0;

  always @(posedge adc_clk) begin
    if (clk_div == 5'd31) begin
      clk_div <= 0;
      ssp_clk_reg <= ~ssp_clk_reg;
    end else begin
      clk_div <= clk_div + 1;
    end
  end
  assign ssp_clk = ssp_clk_reg;

  // Frame generation (16-bit frame)
  reg [3:0] frame_cnt = 0;
  always @(posedge ssp_clk) begin
    frame_cnt <= frame_cnt + 1;
  end
  assign ssp_frame = (frame_cnt == 0) ? 1'b1 : 1'b0;

  // Hysteresis processing
  parameter HIGH_THRESH = 8'hC0;
  parameter LOW_THRESH = 8'h40;
  reg after_hysteresis = 0;

  always @(posedge adc_clk) begin
    if (!after_hysteresis && adc_d >= HIGH_THRESH)
      after_hysteresis <= 1'b1;
    else if (after_hysteresis && adc_d <= LOW_THRESH)
      after_hysteresis <= 1'b0;
  end
  assign dbg = after_hysteresis;

  // Data synchronization
  reg after_hysteresis_sync;
  always @(posedge ssp_clk) begin
    after_hysteresis_sync <= after_hysteresis;
  end
  assign ssp_din = after_hysteresis_sync;

  // Carrier generation
  reg carrier2 = 0;
  always @(posedge adc_clk) begin
    carrier2 <= ~carrier2;
  end

  // Modulation logic
  assign pwr_oe3 = 1'b1;  // Always enabled

  assign pwr_oe1 = (mod_type == 2'b00) ? 1'b1 : 
                   (mod_type == 2'b01) ? (adc_clk ^ after_hysteresis) : 
                   (mod_type[1])       ? (carrier2 ^ after_hysteresis) : 1'b0;

  assign pwr_oe2 = (mod_type == 2'b00) ? 1'b1 : 
                   (mod_type == 2'b01) ? (adc_clk ^ after_hysteresis) : 
                   (mod_type[1])       ? (carrier2 ^ after_hysteresis) : 1'b0;

  assign pwr_oe4 = (mod_type == 2'b00) ? 1'b1 : 
                   (mod_type == 2'b01) ? (adc_clk ^ after_hysteresis) : 
                   (mod_type[1])       ? (carrier2 ^ after_hysteresis) : 1'b0;
endmodule

module usb_fifo_interface (
  input clk,
  input reset,
  input usb_fifo_rxf_n,
  input [7:0] usb_fifo_data,
  output reg usb_fifo_rd_n,
  output reg out_req,
  output [7:0] out_data
);

  // State definitions
  parameter IDLE = 2'b00;
  parameter ASSERT_RD = 2'b01;
  parameter CAPTURE_DATA = 2'b10;
  parameter ACK = 2'b11;

  // Internal signals
  reg [1:0] state, next_state;
  reg [7:0] data_reg;
  reg rxf_n_meta, rxf_n_sync;

  // Synchronizer for usb_fifo_rxf_n
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      rxf_n_meta <= 1'b1;
      rxf_n_sync <= 1'b1;
    end else begin
      rxf_n_meta <= usb_fifo_rxf_n;
      rxf_n_sync <= rxf_n_meta;
    end
  end

  // FSM state register
  always @(posedge clk or posedge reset) begin
    if (reset)
      state <= IDLE;
    else
      state <= next_state;
  end

  // FSM next state logic
  always @(*) begin
    next_state = state;
    case (state)
      IDLE: 
        if (!rxf_n_sync) 
          next_state = ASSERT_RD;
      ASSERT_RD: 
        next_state = CAPTURE_DATA;
      CAPTURE_DATA: 
        next_state = ACK;
      ACK: 
        next_state = IDLE;
    endcase
  end

  // FSM output logic and data capture
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      usb_fifo_rd_n <= 1'b1;
      out_req <= 1'b0;
      data_reg <= 8'b0;
    end else begin
      case (state)
        IDLE: 
          begin
            usb_fifo_rd_n <= 1'b1;
            out_req <= 1'b0;
          end
        ASSERT_RD: 
          usb_fifo_rd_n <= 1'b0;
        CAPTURE_DATA: 
          begin
            usb_fifo_rd_n <= 1'b1;
            data_reg <= usb_fifo_data;
          end
        ACK: 
          out_req <= 1'b1;
      endcase
    end
  end

  // Data output assignment
  assign out_data = data_reg;

endmodule
